+                Builder.SetInsertPoint(I);
+                Type *GEPIndexType =
+                    DL.getIndexType(GEP->getPointerOperand()->getType());
+                NewPtrOperand = Builder.CreateGEP(
+                    GEP->getSourceElementType(), InnerPtr,
+                    ConstantInt::get(GEPIndexType, MaskedGEPIndex),
+                    GEP->getName(), GEP->isInBounds());
+              } else {
+                auto *GEPOp = cast<GEPOperator>(PtrOperand);
+                Type *GEPIndexType =
+                    DL.getIndexType(GEPOp->getPointerOperand()->getType());
+                NewPtrOperand = ConstantExpr::getGetElementPtr(
+                    GEPOp->getSourceElementType(), cast<Constant>(InnerPtr),
+                    ConstantInt::get(GEPIndexType, MaskedGEPIndex),
+                    GEPOp->isInBounds());
+              }
+              replaceOperand(*I, 0, NewPtrOperand);
               return I;
             }
